const { Inconvo } = require('@inconvoai/node');
const fs = require('fs');
const path = require('path');

async function main() {
  const apiKey = process.env.INCONVO_API_KEY;
  const agentId = process.env.INCONVO_AGENT_ID;

  if (!apiKey || !agentId) {
    console.error('INCONVO_API_KEY and INCONVO_AGENT_ID must be set');
    process.exit(1);
  }

  const inconvo = new Inconvo({
    apiKey: apiKey,
  });

  try {
    console.log('Creating conversation...');
    const conversation = await inconvo.agents.conversations.create(agentId, {
      userIdentifier: 'user-123',
      userContext: {},
    });

    console.log(`Conversation created: ${conversation.id}`);

    console.log('Sending message...');
    const response = await inconvo.agents.conversations.response.create(
      agentId,
      conversation.id,
      {
        message: 'Show me the sales trend as a chart.',
        stream: false,
      }
    );

    console.log('Response received.');
    fs.writeFileSync(
      path.join(__dirname, 'response.json'),
      JSON.stringify(response, null, 2)
    );
    console.log('Response saved to response.json');
  } catch (error) {
    console.error('Error:', error);
    process.exit(1);
  }
}

main();

